import React from 'react';
import { TabDashboard } from './TabDashboard';
import './styles.css';

const tabs = [
  { id: 'users', label: 'Users', items: Array.from({ length: 2000 }, (_, i) => `User ${i + 1} — ${['Active', 'Inactive', 'Pending'][i % 3]}`) },
  { id: 'orders', label: 'Orders', items: Array.from({ length: 2000 }, (_, i) => `Order #${10000 + i} — ${['Shipped', 'Processing', 'Delivered'][i % 3]}`) },
  { id: 'products', label: 'Products', items: Array.from({ length: 2000 }, (_, i) => `Product ${i + 1} — ${['Electronics', 'Clothing', 'Books'][i % 3]}`) },
];

export default function App() {
  return (
    <div style={{ padding: '2rem', fontFamily: 'system-ui, sans-serif', maxWidth: '36rem' }}>
      <h1 style={{ marginBottom: '1.5rem' }}>Concurrent Dashboard</h1>
      <TabDashboard tabs={tabs} />
    </div>
  );
}

import React, { useState } from 'react';
import './styles.css';

interface TabData {
  id: string;
  label: string;
  items: string[];
}

interface TabDashboardProps {
  tabs: TabData[];
}

// TODO: Use useTransition for tab switches
// TODO: Use useDeferredValue for search within tab panel
// TODO: Show pending indicator during transition
// TODO: Show stale state for deferred search results

export const TabDashboard: React.FC<TabDashboardProps> = ({ tabs }) => {
  const [activeTab, setActiveTab] = useState(tabs[0].id);
  const [search, setSearch] = useState('');

  const currentTab = tabs.find(t => t.id === activeTab)!;

  // BUG: This blocks the main thread during tab switch
  const filtered = currentTab.items.filter(item =>
    item.toLowerCase().includes(search.toLowerCase())
  );

  return (
    <div className="ctab">
      {/* Tab bar */}
      <div className="ctab__bar">
        {tabs.map(tab => (
          <button
            key={tab.id}
            data-testid={`tab-${tab.id}`}
            className={`ctab__btn${tab.id === activeTab ? ' ctab__btn--active' : ''}`}
            onClick={() => {
              setActiveTab(tab.id);
              setSearch('');
            }}
          >
            {tab.label}
          </button>
        ))}
        {/* TODO: Pending indicator */}
      </div>

      {/* Search */}
      <input
        data-testid="tab-search"
        className="ctab__search"
        placeholder={`Search ${currentTab.label.toLowerCase()}…`}
        value={search}
        onChange={e => setSearch(e.target.value)}
      />

      {/* Tab panel */}
      <div data-testid="tab-panel" className="ctab__panel">
        {/* TODO: Stale indicator */}
        <div data-testid="results-list" className="ctab__list">
          {filtered.slice(0, 50).map((item, i) => (
            <div key={i} className="ctab__item">{item}</div>
          ))}
        </div>
      </div>
    </div>
  );
};

.ctab {
  border: 1px solid #e5e7eb;
  border-radius: 0.5rem;
  overflow: hidden;
}

.ctab__bar {
  display: flex;
  align-items: center;
  gap: 0;
  border-bottom: 1px solid #e5e7eb;
  background: #f9fafb;
}

.ctab__btn {
  flex: 1;
  padding: 0.625rem 1rem;
  border: none;
  background: transparent;
  font-size: 0.875rem;
  font-weight: 500;
  color: #6b7280;
  cursor: pointer;
  border-bottom: 2px solid transparent;
}

.ctab__btn:hover {
  color: #374151;
}

.ctab__btn--active {
  color: #3b82f6;
  border-bottom-color: #3b82f6;
}

.ctab__pending {
  display: inline-flex;
  align-items: center;
  padding: 0 0.75rem;
  font-size: 0.75rem;
  color: #f59e0b;
}

.ctab__search {
  width: 100%;
  padding: 0.5rem 1rem;
  border: none;
  border-bottom: 1px solid #e5e7eb;
  font-size: 0.875rem;
}

.ctab__search:focus {
  outline: none;
  background: #f0f9ff;
}

.ctab__panel {
  padding: 0;
  max-height: 20rem;
  overflow-y: auto;
}

.ctab__panel--stale {
  opacity: 0.6;
  transition: opacity 0.2s;
}

.ctab__list {
  display: flex;
  flex-direction: column;
}

.ctab__item {
  padding: 0.5rem 1rem;
  font-size: 0.8125rem;
  color: #374151;
  border-bottom: 1px solid #f3f4f6;
}

.ctab__item:hover {
  background: #f9fafb;
}

