import { render, screen, fireEvent } from '@testing-library/react';
import '@testing-library/jest-dom';
import React from 'react';
import App from './App';

describe('Concurrent Transitions', () => {
  it('renders tab buttons', () => {
    render(<App />);
    expect(screen.getByTestId('tab-users')).toBeInTheDocument();
    expect(screen.getByTestId('tab-orders')).toBeInTheDocument();
    expect(screen.getByTestId('tab-products')).toBeInTheDocument();
  });

  it('first tab is active by default', () => {
    render(<App />);
    expect(screen.getByTestId('tab-users')).toHaveClass('ctab__btn--active');
  });

  it('clicking a tab switches active state', () => {
    render(<App />);
    fireEvent.click(screen.getByTestId('tab-orders'));
    expect(screen.getByTestId('tab-orders')).toHaveClass('ctab__btn--active');
  });

  it('renders tab panel with results', () => {
    render(<App />);
    expect(screen.getByTestId('results-list').children.length).toBeGreaterThan(0);
  });

  it('search input filters results', () => {
    render(<App />);
    fireEvent.change(screen.getByTestId('tab-search'), { target: { value: 'active' } });
    const results = screen.getByTestId('results-list');
    if (results.children.length > 0) {
      expect(results.children[0].textContent?.toLowerCase()).toContain('active');
    }
  });

  it('uses useTransition (pending element exists in markup)', () => {
    render(<App />);
    // The pending element should exist in the DOM structure even if hidden
    // It may or may not be visible depending on transition state
    const tabPanel = screen.getByTestId('tab-panel');
    expect(tabPanel).toBeInTheDocument();
  });

  it('search input clears on tab switch', () => {
    render(<App />);
    fireEvent.change(screen.getByTestId('tab-search'), { target: { value: 'test' } });
    fireEvent.click(screen.getByTestId('tab-orders'));
    expect(screen.getByTestId('tab-search')).toHaveValue('');
  });
});

