import React, { useState, useTransition, useDeferredValue, memo, useMemo } from 'react';
import './styles.css';

interface TabData {
  id: string;
  label: string;
  items: string[];
}

interface TabDashboardProps {
  tabs: TabData[];
}

interface TabPanelProps {
  items: string[];
  search: string;
}

const TabPanel = memo<TabPanelProps>(({ items, search }) => {
  const deferredSearch = useDeferredValue(search);
  const isStale = deferredSearch !== search;

  const filtered = useMemo(
    () => items.filter(item => item.toLowerCase().includes(deferredSearch.toLowerCase())),
    [items, deferredSearch]
  );

  return (
    <div data-testid="tab-panel" className={`ctab__panel${isStale ? ' ctab__panel--stale' : ''}`}>
      {isStale && <span data-testid="stale" className="ctab__pending">Filtering…</span>}
      <div data-testid="results-list" className="ctab__list">
        {filtered.slice(0, 50).map((item, i) => (
          <div key={i} className="ctab__item">{item}</div>
        ))}
      </div>
    </div>
  );
});

export const TabDashboard: React.FC<TabDashboardProps> = ({ tabs }) => {
  const [activeTab, setActiveTab] = useState(tabs[0].id);
  const [search, setSearch] = useState('');
  const [isPending, startTransition] = useTransition();

  const currentTab = tabs.find(t => t.id === activeTab)!;

  const handleTabSwitch = (tabId: string) => {
    setSearch('');
    startTransition(() => {
      setActiveTab(tabId);
    });
  };

  return (
    <div className="ctab">
      <div className="ctab__bar">
        {tabs.map(tab => (
          <button
            key={tab.id}
            data-testid={`tab-${tab.id}`}
            className={`ctab__btn${tab.id === activeTab ? ' ctab__btn--active' : ''}`}
            onClick={() => handleTabSwitch(tab.id)}
          >
            {tab.label}
          </button>
        ))}
        {isPending && <span data-testid="pending" className="ctab__pending">Loading…</span>}
      </div>

      <input
        data-testid="tab-search"
        className="ctab__search"
        placeholder={`Search ${currentTab.label.toLowerCase()}…`}
        value={search}
        onChange={e => setSearch(e.target.value)}
      />

      <TabPanel items={currentTab.items} search={search} />
    </div>
  );
};
